    uint32_t t_on  = (uint32_t)(mstart[rs[0]]   + start_day - 1) * 1440 + rs[3] * 60 + rs[4];
    uint32_t t_off = (uint32_t)(mstart[re[0]]   + end_day   - 1) * 1440 + re[3] * 60 + re[4];

