    memset(&result, 0, sizeof(result));

    int32_t ilon = (int32_t)(lon * 100.0f + (lon >= 0 ? 0.5f : -0.5f));
    int32_t ilat = (int32_t)(lat * 100.0f + (lat >= 0 ? 0.5f : -0.5f));

